class Solution {
public:
    // Function to compute XOR from 0 to n
    int xorUpto(int n) {
        int mod = n % 4;
        if(mod == 0) return n;
        if(mod == 1) return 1;
        if(mod == 2) return n + 1;
        return 0; // mod == 3
    }

    int rangeXOR(int L, int R) {
        return xorUpto(R) ^ xorUpto(L - 1);
    }
};

