class Solution:
    def xor_upto(self, n: int) -> int:
        """Compute XOR of all numbers from 0 to n"""
        mod = n % 4
        if mod == 0:
            return n
        elif mod == 1:
            return 1
        elif mod == 2:
            return n + 1
        else:  # mod == 3
            return 0

    def rangeXOR(self, L: int, R: int) -> int:
        return self.xor_upto(R) ^ self.xor_upto(L - 1)

