class Solution{
    rangeXOR(L, R) {
    // Helper function to compute XOR from 0 to n in O(1) time
    function computeXOR(n) {
        if (n < 0) return 0;
        let mod = n % 4;

        if (mod === 0) return n;
        if (mod === 1) return 1;
        if (mod === 2) return n + 1;
        return 0; // mod === 3
    }

    // XOR of range [L, R] is XOR(0..R) ^ XOR(0..L-1)
    return computeXOR(R) ^ computeXOR(L - 1);
}

